"""Тесты этапа ImageProcessingStage."""from __future__ import annotationsfrom pathlib import Pathfrom src.modules.file_extract.models import (    ExtractedDocumentContent,    SEMANTIC_TYPE_REQUIRED_DETECTION,)from src.modules.project.project_config import ProjectConfigfrom src.modules.project.sections.image_processing_config import ImageProcessingConfigfrom src.modules.project.sections.pipeline_config import KEY_IMAGE_PROCESSING_THREADSfrom src.modules.project_pipeline.models import PipelineContextfrom src.modules.project_pipeline.stages import ImageProcessingStagedef test_get_max_workers_returns_one_for_ocr(tmp_path: Path) -> None:    config = ProjectConfig.create_default(tmp_path)    config.image_processing["image_processing_logic"] = (        ImageProcessingConfig.IMAGE_PROCESSING_LOGICS.ocr_only    )    config.pipeline[KEY_IMAGE_PROCESSING_THREADS] = 8    stage = ImageProcessingStage()    assert stage._get_max_workers(config) == 1def test_get_max_workers_uses_pipeline_config_for_vision(tmp_path: Path) -> None:    config = ProjectConfig.create_default(tmp_path)    config.image_processing["image_processing_logic"] = (        ImageProcessingConfig.IMAGE_PROCESSING_LOGICS.vision_only    )    config.pipeline[KEY_IMAGE_PROCESSING_THREADS] = 3    stage = ImageProcessingStage()    assert stage._get_max_workers(config) == 3def test_execute_item_dispatches_to_vision_processing(    tmp_path: Path, monkeypatch) -> None:    class NoOpLogger:        def debug(self, msg: object, *args: object, **kwargs: object) -> None: ...        def info(self, msg: object, *args: object, **kwargs: object) -> None: ...        def warning(self, msg: object, *args: object, **kwargs: object) -> None: ...        def error(self, msg: object, *args: object, **kwargs: object) -> None: ...        def exception(self, msg: object, *args: object, **kwargs: object) -> None: ...    config = ProjectConfig.create_default(tmp_path)    config.image_processing["image_processing_logic"] = (        ImageProcessingConfig.IMAGE_PROCESSING_LOGICS.vision_only    )    item = ExtractedDocumentContent(        content_type="image",        semantic_type=SEMANTIC_TYPE_REQUIRED_DETECTION,        path=tmp_path / "image.png",        mime_type="image/png",    )    stage = ImageProcessingStage()    context = PipelineContext(config=config, logger=NoOpLogger(), cancel_event=None)    called: list[str] = []    def fake_vision_processing(ctx, content_item):        called.append("vision")        return content_item    monkeypatch.setattr(stage, "_vision_processing", fake_vision_processing)    result = stage._execute_item(context, item)    assert result is item    assert called == ["vision"]